@startuml
enum Position {
  GK
  LB
}
enum Recommendation {
  KEY_PLAYER
  FIRST_TEAM_PLAYER
  RESERVE_TEAM_PLAYER
  PROSPECTIVE_PLAYER
  NOT_RECOMMENDED
}
enum ScoutingStatus {
  LONG_LISTED
  SHORT_LISTED
  RECOMMENDED_FOR_SIGNING
  OFFER_MADE
}
enum ScoutKind {
  REGULAR_SCOUNT
  HEAD_SCOUT
}

abstract class Person {
  - firstName : string
  - lastName : string
}
class TSS
class Player {
  status : ScoutingStatus
}
class HeadCoach
class Director
class Scout {
  scoutKind : ScoutKind
}
class Club
class Offer {
  value : int
}
class ScoutingAssignmnet
class ScoutingAssignment
class ScoutReport {
  pro : string
  con : string
  recommendation : Recommendation
}
class PlayerProfile {
  position : Position
}
class PlayerAttribute {
  name : string
  value : int
}

TSS *-- Person
TSS *-- ScoutingAssignment
TSS *-- PlayerProfile
TSS *-- Club

Director *-- Offer

Club "1" -- "0..1" Director
Club "1" -- "0..1" HeadCoach
Club *-- Player
Club *-- Scout

Scout *-- ScoutingAssignment

ScoutingAssignment *-- "0..1" ScoutReport

HeadCoach *-- PlayerProfile

PlayerProfile *-- PlayerAttribute

Player --|> Person
HeadCoach --|> Person
Director --|> Person
Scout --|> Person

Offer "0..1" -- Player
Player "0..1" -- "0..1" PlayerProfile
ScoutReport "1" -- "1" ScoutReport

@enduml

